<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>NewsPilot Demo</title>
    <style>
        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }

        body {
            min-height: 100vh;
            display: flex;
            align-items: center;
            justify-content: center;
            font-family: Arial, Helvetica, sans-serif;
            background: linear-gradient(135deg, #f8fbff 0%, #eef7ff 45%, #f7fffe 100%);
            color: #0f172a;
        }

        .demo-wrapper {
            width: 100%;
            max-width: 760px;
            padding: 40px 24px;
            text-align: center;
        }

        .logo {
            display: block;
            width: 320px;
            max-width: 86%;
            height: auto;
            margin: 0 auto 34px;
        }

        .open-demo-btn {
            display: inline-flex;
            align-items: center;
            justify-content: center;
            min-width: 190px;
            padding: 15px 36px;
            border-radius: 999px;
            background: linear-gradient(135deg, #0757a8 0%, #05bfc4 100%);
            color: #ffffff;
            font-size: 18px;
            font-weight: 700;
            text-decoration: none;
            box-shadow: 0 14px 30px rgba(7, 87, 168, 0.22);
            transition: transform 0.2s ease, box-shadow 0.2s ease;
        }

        .open-demo-btn:hover {
            transform: translateY(-2px);
            box-shadow: 0 18px 38px rgba(7, 87, 168, 0.28);
        }

        .open-demo-btn:active {
            transform: translateY(0);
        }
    </style>
</head>
<body>
<main class="demo-wrapper">
    <img class="logo" src="data:image/png;base64," alt="NewsPilot">

    <a class="open-demo-btn" href="https://newspilot.clustercoding.com" target="_blank" rel="noopener noreferrer">
        Open Demo
    </a>
</main>
</body>
</html>
